document.addEventListener('DOMContentLoaded', function () {
    const heading = document.querySelector('.wrap .wp-heading-inline + .page-title-action');

    if (heading) {
        const btn = document.createElement('a');
        btn.href = BRANDBERRY_PAGE_IMPORT.page_url;
        btn.style.top = "0";
        btn.style.left = "5px";
        btn.style.border = "1px solid #1f0803ff";
        btn.style.borderRadius = "6px";
        btn.style.padding = "0 8px";
        btn.id = 'brandberry-heading-button';
        btn.className = 'page-title-action'; // same styling as Add New
        // btn.innerText = 'Import Page';   
        if (BRANDBERRY_PAGE_IMPORT?.logo && BRANDBERRY_PAGE_IMPORT.logo != '') {
            btn.innerHTML = `
                <div style="display: flex; 
                    justify-content: center; 
                    align-items: center; 
                    gap: 6px; 
                "><img src="${BRANDBERRY_PAGE_IMPORT.logo}" /> <span style="font-size: 12px; font-weight: 500; color: #FFFFFF">Theme Page Import </span></div>
                `;
        } else {
            btn.innerHTML = `
                <div style="display: flex; 
                    justify-content: center; 
                    align-items: center; 
                    gap: 6px; 
                "><span style="font-size: 12px; font-weight: 500; color: #FFFFFF">import page</span></div>
                `;
        }

        heading.after(btn);
    }
});